import React, { useState } from 'react';

export default function AdminBookForm({ onSubmit, initialData = {}, loading }) {
  const [form, setForm] = useState({
    title: initialData.title || '',
    author: initialData.author || '',
    category: initialData.category || '',
    isbn: initialData.isbn || '',
    aisle: initialData.aisle || '',
    shelf: initialData.shelf || '',
    quantity: initialData.quantity || 1,
  });
  const [error, setError] = useState('');

  function handleChange(e) {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    if (!form.title || !form.author || !form.aisle || !form.shelf) {
      setError('Title, Author, Aisle, and Shelf are required.');
      return;
    }
    setError('');
    onSubmit(form);
  }

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-2xl shadow-lg p-8 max-w-xl mx-auto border border-gray-200" aria-label="Add or edit book form">
      <h2 className="text-2xl font-extrabold mb-6 tracking-tight text-blue-800">{initialData.id ? 'Edit Book' : 'Add New Book'}</h2>
      <div className="grid gap-6">
        <label htmlFor="title" className="block font-semibold text-gray-800">Title
          <input id="title" name="title" type="text" className="mt-2 w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600 text-lg" value={form.title} onChange={handleChange} aria-required="true" />
        </label>
        <label htmlFor="author" className="block font-semibold text-gray-800">Author
          <input id="author" name="author" type="text" className="mt-2 w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600 text-lg" value={form.author} onChange={handleChange} aria-required="true" />
        </label>
        <label htmlFor="category" className="block font-semibold text-gray-800">Category
          <input id="category" name="category" type="text" className="mt-2 w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600 text-lg" value={form.category} onChange={handleChange} />
        </label>
        <label htmlFor="isbn" className="block font-semibold text-gray-800">ISBN
          <input id="isbn" name="isbn" type="text" className="mt-2 w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600 text-lg" value={form.isbn} onChange={handleChange} />
        </label>
        <div className="flex gap-4">
          <label htmlFor="aisle" className="flex-1 block font-semibold text-gray-800">Aisle
            <input id="aisle" name="aisle" type="text" className="mt-2 w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600 text-lg" value={form.aisle} onChange={handleChange} aria-required="true" />
          </label>
          <label htmlFor="shelf" className="flex-1 block font-semibold text-gray-800">Shelf
            <input id="shelf" name="shelf" type="text" className="mt-2 w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600 text-lg" value={form.shelf} onChange={handleChange} aria-required="true" />
          </label>
        </div>
        <label htmlFor="quantity" className="block font-semibold text-gray-800">Quantity
          <input id="quantity" name="quantity" type="number" min="0" className="mt-2 w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600 text-lg" value={form.quantity} onChange={handleChange} />
        </label>
      </div>
      {error && <div className="text-red-700 mt-4 text-base font-semibold" role="alert">{error}</div>}
      <button type="submit" className="mt-8 w-full py-3 bg-blue-700 hover:bg-blue-800 transition-colors text-white rounded-lg font-bold text-lg focus:outline-none focus:ring-2 focus:ring-blue-600 shadow-sm disabled:opacity-60" disabled={loading} aria-busy={loading} aria-label={initialData.id ? 'Update book' : 'Add book'}>
        {loading ? 'Saving...' : (initialData.id ? 'Update Book' : 'Add Book')}
      </button>
    </form>
  );
}
